code = """import json
import re

citations_file = locals()['var_function-call-8931525846963248243']
with open(citations_file, 'r') as f:
    citations = json.load(f)

batch1_file = locals()['var_function-call-518311545790473343']
batch2_file = locals()['var_function-call-7503366853811892685']

with open(batch1_file, 'r') as f:
    papers1 = json.load(f)
with open(batch2_file, 'r') as f:
    papers2 = json.load(f)

papers = papers1 + papers2

# Create citation map
citation_map = {}
for c in citations:
    try:
        count = int(c['citation_count'])
    except:
        count = 0
    citation_map[c['title']] = count

total_citations = 0
chi_papers = []

for p in papers:
    if not p['filename'].endswith('.txt'):
        continue
    title = p['filename'][:-4]
    
    if title in citation_map:
        text = p['text']
        header = text[:5000] # Check first 5000 chars
        
        is_chi = False
        
        # Strict check for venue
        # 1. "Conference on Human Factors in Computing Systems"
        if "Conference on Human Factors in Computing Systems" in header:
            is_chi = True
        # 2. CHI followed by year or 'Conference'
        # Regex: \bCHI\s+(?:['\u2019]?\d{2}|Conference)
        # matches "CHI '15", "CHI 2015", "CHI Conference"
        elif re.search(r"\bCHI\s+(?:['\u2019]?\d{2}|Conference)", header, re.IGNORECASE):
            is_chi = True
        
        # 3. Proceedings of the CHI
        elif "Proceedings of the CHI" in header:
            is_chi = True

        if is_chi:
            total_citations += citation_map[title]
            chi_papers.append(title)

print("__RESULT__:")
print(json.dumps({"total_citations": total_citations, "chi_paper_count": len(chi_papers), "chi_papers_list": chi_papers}))"""

